#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
int T,n,p;
vector<pii> ask;
stack<int> a,b,c;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    T=read();
    while(T--){
        n=read(),p=read();
        ask.clear();

        while(!a.empty())a.pop();
        while(!b.empty())b.pop();
        while(!c.empty())c.pop();

        for(int i=1;i<=n;i++){
            char h;cin>>h;
            if(a.empty()||a.top()!=h-'0')
                a.push(h-'0');
        }
        for(int i=1;i<=n;i++){
            char h;cin>>h;
            if(b.empty()||b.top()!=h-'0')
                b.push(h-'0');
        }

        //while(!a.empty()){cout<<a.top()<<" ";a.pop();}
        //while(!b.empty()){cout<<b.top()<<" ";b.pop();}


        while(1){
            //cout<<a.size()<<" "<<b.size()<<"!!!\n";
            if(a.size()==1&&b.size()==1&&a.top()!=b.top()){
                //cout<<"a.size()==1&&b.size()==1\n";
                if(c.size()){
                    if(c.top()==a.top())ask.pb({3,1});
                    else ask.pb({3,2});
                }break;
            }
            if(a.empty()){
                //cout<<"a.empty()\n";
                if(b.size()==1){
                    a.push(c.top()),c.pop();
                    ask.pb({3,1});break;
                }
                ask.pb({2,1}),a.push(b.top()),b.pop();
                continue;
            }
            if(b.empty()){
                //cout<<"b.empty()\n";
                if(a.size()==1){
                    b.push(c.top()),c.pop();
                    ask.pb({3,2});break;
                }
                ask.pb({1,2}),b.push(a.top()),a.pop();
                continue;
            }
            if(a.top()==b.top()){
                //cout<<"a.top()==b.top()\n";
                if(a.size()>=b.size())a.pop(),ask.pb({1,2});
                else b.pop(),ask.pb({2,1});
                continue;
            }
            if(c.empty()){
                //cout<<"c.empty()\n";
                if(a.size()>=b.size())
                    c.push(a.top()),a.pop(),ask.pb({1,3});
                else c.push(b.top()),b.pop(),ask.pb({2,3});
                continue;
            }
            if(a.top()==c.top()){
                //cout<<"a.top()==c.top()\n";
                a.pop(),ask.pb({1,3});
                continue;
            }
            if(b.top()==c.top()){
                //cout<<"b.top()==c.top()\n";
                b.pop(),ask.pb({2,3});
                continue;
            }

            cout<<"WHAT?!?!\n";
        }

        cout<<ask.size()<<"\n";
        if(p==1)continue;
        for(auto [x,y]:ask)cout<<x<<" "<<y<<"\n";
    }
    return 0;
}
